  return 0;
}

// Mock 2 — max-finder variant
struct stat_double { double mystery; double numbers[5]; };

void who_am_i(stat_double &data) {
  data.mystery = data.numbers[0];
  for (int i = 1; i < 5; i++) {
    if (data.numbers[i] > data.mystery)
      data.mystery = data.numbers[i];
  }
}

void read_stat(stat_double &list[], int count) {
  for (int i = 0; i < count; i++) {
    for (int j = 0; j < 5; j++) {
      cin >> list[i].numbers[j];
    }
  }
}

int main() {
  const int MAX = 100;
  stat_double list[MAX];
  int count;
  cin >> count;
  read_stat(list, count);
  return 0;
}

